19	const PROCESSING_FEE = 5;
20	
21	const BASE_PRICE_BY_TYPE: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	const basePriceFor = (item: Item): number => BASE_PRICE_BY_TYPE[item.type];
31	
32	const COMPONENT_BLOCK_SIZE = 3;
33	const COMPONENT_BLOCK_PRICE = 60;
34	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
35	
36	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
37	
38	const sumBasePrices = (items: Item[]): number =>
39	  items.reduce((s, i) => s + basePriceFor(i), 0);
40	
41	const groupByType = (items: Item[]): Map<string, Item[]> => {
42	  const map = new Map<string, Item[]>();
43	  for (const item of items) {
44	    const list = map.get(item.type) ?? [];
45	    list.push(item);
46	    map.set(item.type, list);
47	  }
48	  return map;
49	};
50	
51	const componentsPremium = (components: Item[]): number => {
52	  let total = 0;
53	  for (const group of groupByType(components).values()) {
54	    total += group.length === COMPONENT_BLOCK_SIZE
55	      ? COMPONENT_BLOCK_PRICE
56	      : sumBasePrices(group);
57	  }
58	  return total;
59	};
60	
61	const itemsBasePremium = (items: Item[]): number => {
62	  const components = items.filter(isComponent);
63	  const nonComponents = items.filter((i) => !isComponent(i));
64	  return sumBasePrices(nonComponents) + componentsPremium(components);
65	};
66	
67	const quotePremium = (step: QuoteStep): number =>
68	  itemsBasePremium(step.items) + PROCESSING_FEE;
69	
70	export const runScenario = (scenario: Scenario): ScenarioResult => ({
71	  results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
72	});
